detect_flaky_tests() {
  [ $# -ge 2 ] || { echo '{}'; return 1; }

  local tmpfile
  tmpfile=$(mktemp)
  trap "rm -f $tmpfile" RETURN

  # Collect all test results across runs
  local file
  for file in "$@"; do
    # Use awk to handle multiline testcase elements
    awk '
      /<testcase/ {
        name = $0
        gsub(/.*name="/, "", name)
        gsub(/".*/, "", name)
        has_failure = 0
      }
      /<failure/ { has_failure = 1 }
      /<\/testcase>|\/\>/ {
        if (name != "") {
          status = has_failure ? "failed" : "passed"
          print name ":" status
          name = ""
          has_failure = 0
        }
      }
    ' "$file"
  done | sort > "$tmpfile"

  # Find tests with mixed results (flaky)
  awk -F: '{status[$1][$2]++} END {
    for (test in status) {
      count = 0
      for (s in status[test]) count++
      if (count > 1) {
        print test
      }
    }
  }' "$tmpfile"
}

