#!/usr/bin/env bash
# Test results aggregator: parses JUnit XML and JSON test results,
# aggregates across multiple files, detects flaky tests, and generates markdown summaries.
set -euo pipefail

parse_junit_xml() {
  local xml_file="$1"
  [ -f "$xml_file" ] || return 1

  # Extract test counts from XML using grep and sed
  local tests failed skipped passed
  tests=$(grep -oP 'tests="\K[0-9]+' "$xml_file" | head -1)
  failed=$(grep -oP 'failures="\K[0-9]+' "$xml_file" | head -1)
  skipped=$(grep -oP 'skipped="\K[0-9]+' "$xml_file" | head -1)
  passed=$((tests - failed - skipped))

  # Output as JSON-like format
  printf '{"passed":%d,"failed":%d,"skipped":%d,"total":%d}\n' "$passed" "$failed" "$skipped" "$tests"
}

parse_json_results() {
  local json_file="$1"
  [ -f "$json_file" ] || return 1

  # Extract counts from JSON
  local passed failed skipped
  passed=$(jq -r '.passed // 0' "$json_file")
  failed=$(jq -r '.failed // 0' "$json_file")
  skipped=$(jq -r '.skipped // 0' "$json_file")

  printf '{"passed":%d,"failed":%d,"skipped":%d}\n' "$passed" "$failed" "$skipped"
}

aggregate_junit_files() {
  [ $# -gt 0 ] || { echo '{"error":"No files provided"}'; return 1; }

  local total_passed=0 total_failed=0 total_skipped=0
  local file

  for file in "$@"; do
    local result
    result=$(parse_junit_xml "$file") || continue

    local p f s
    p=$(echo "$result" | jq -r '.passed')
    f=$(echo "$result" | jq -r '.failed')
    s=$(echo "$result" | jq -r '.skipped')

    total_passed=$((total_passed + p))
    total_failed=$((total_failed + f))
    total_skipped=$((total_skipped + s))
  done

  printf '{"total_passed":%d,"total_failed":%d,"total_skipped":%d}\n' "$total_passed" "$total_failed" "$total_skipped"
}

detect_flaky_tests() {
  [ $# -ge 2 ] || { echo '{}'; return 1; }

  local tmpfile
  tmpfile=$(mktemp)
  trap "rm -f $tmpfile" RETURN

  # Collect all test results across runs
  local file
  for file in "$@"; do
    # Use awk to handle multiline testcase elements
    awk '
      /<testcase/ {
        name = $0
        gsub(/.*name="/, "", name)
        gsub(/".*/, "", name)
        has_failure = 0
      }
      /<failure/ { has_failure = 1 }
      /<\/testcase>|\/\>/ {
        if (name != "") {
          status = has_failure ? "failed" : "passed"
          print name ":" status
          name = ""
          has_failure = 0
        }
      }
    ' "$file"
  done | sort > "$tmpfile"

  # Find tests with mixed results (flaky)
  awk -F: '{status[$1][$2]++} END {
    for (test in status) {
      count = 0
      for (s in status[test]) count++
      if (count > 1) {
        print test
      }
    }
  }' "$tmpfile"
}

generate_markdown_summary() {
  local total_passed=0 total_failed=0 total_skipped=0 total_duration=0

  # Parse key=value arguments
  while [[ $# -gt 0 ]]; do
    case "$1" in
      total_passed=*) total_passed="${1#*=}" ;;
      total_failed=*) total_failed="${1#*=}" ;;
      total_skipped=*) total_skipped="${1#*=}" ;;
      total_duration=*) total_duration="${1#*=}" ;;
    esac
    shift
  done

  cat <<EOF
# Test Results Summary

## Summary Statistics

- **Passed**: $total_passed
- **Failed**: $total_failed
- **Skipped**: $total_skipped
- **Duration**: ${total_duration}s

EOF
}

main() {
  [ $# -gt 0 ] || { echo "Usage: $0 <result-files...>"; return 1; }
}

# Allow sourcing for tests
if [[ "${BASH_SOURCE[0]}" == "${0}" ]]; then
  main "$@"
fi

